// conformance/src/runtime.rs

/// Trait abstracting over async runtimes.
pub trait ConformanceRuntime: Send + Sync + 'static {
    /// Runtime name for logging.
    fn name(&self) -> &'static str;

    /// Run a future to completion.
    fn block_on<F: Future>(&self, future: F) -> F::Output;

    /// Spawn a task.
    fn spawn<F>(&self, future: F) -> Box<dyn Future<Output = F::Output> + Send>
    where
        F: Future + Send + 'static,
        F::Output: Send + 'static;

    /// Sleep for a duration.
    fn sleep(&self, duration: Duration) -> Box<dyn Future<Output = ()> + Send>;

    /// Create a timeout wrapper.
    fn timeout<F: Future>(
        &self,
        duration: Duration,
        future: F,
    ) -> Box<dyn Future<Output = Result<F::Output, TimeoutError>> + Send>;

    /// Create an MPSC channel.
    fn mpsc_channel<T: Send + 'static>(
        &self,
        capacity: usize,
    ) -> (Box<dyn MpscSender<T>>, Box<dyn MpscReceiver<T>>);

    /// Create a mutex.
    fn mutex<T: Send + 'static>(&self, value: T) -> Box<dyn AsyncMutex<T>>;

    // ... more primitives
}

/// Asupersync runtime adapter.
pub struct AsupersyncRuntime {
    lab: LabRuntime,
}

impl ConformanceRuntime for AsupersyncRuntime {
    fn name(&self) -> &'static str { "asupersync" }

    fn block_on<F: Future>(&self, future: F) -> F::Output {
        self.lab.run(future)
    }

    // ... implementations
}

/// Tokio runtime adapter.
pub struct TokioRuntime {
    rt: tokio::runtime::Runtime,
}

impl ConformanceRuntime for TokioRuntime {
    fn name(&self) -> &'static str { "tokio" }

    fn block_on<F: Future>(&self, future: F) -> F::Output {
        self.rt.block_on(future)
    }

    // ... implementations
}
