// conformance/src/runner.rs

use tracing::{info, warn, error, debug, span, Level};

/// Configuration for test execution.
pub struct RunConfig {
    /// Categories to run (empty = all).
    pub categories: Vec<TestCategory>,
    /// Tags to filter by.
    pub tags: Vec<String>,
    /// Specific test IDs to run.
    pub test_ids: Vec<String>,
    /// Number of parallel tests.
    pub parallelism: usize,
    /// Timeout per test.
    pub timeout: Duration,
    /// Run on both runtimes and compare.
    pub compare_mode: bool,
    /// Log level.
    pub log_level: Level,
}

/// Test runner that executes conformance tests.
pub struct TestRunner {
    asupersync: AsupersyncRuntime,
    tokio: TokioRuntime,
    config: RunConfig,
    results: Vec<ComparisonResult>,
}

/// Result of running a test on both runtimes.
#[derive(Debug, Serialize)]
pub struct ComparisonResult {
    pub test_id: String,
    pub test_name: String,
    pub category: TestCategory,
    pub asupersync_result: TestResult,
    pub tokio_result: TestResult,
    pub comparison: ComparisonStatus,
}

#[derive(Debug, Serialize)]
pub enum ComparisonStatus {
    /// Both passed with equivalent outputs.
    BothPassedEquivalent,
    /// Both passed but outputs differ (might be acceptable).
    BothPassedDifferent { diff: String },
    /// Both failed with same error.
    BothFailedSame,
    /// Both failed with different errors.
    BothFailedDifferent,
    /// Asupersync passed, Tokio failed (unexpected!).
    AsupersyncOnlyPassed,
    /// Tokio passed, Asupersync failed (bug in asupersync).
    TokioOnlyPassed { error: String },
}

impl TestRunner {
    pub fn new(config: RunConfig) -> Self {
        Self {
            asupersync: AsupersyncRuntime::new(),
            tokio: TokioRuntime::new(),
            config,
            results: Vec::new(),
        }
    }

    /// Run all matching tests.
    pub fn run_all(&mut self, tests: &[TestCase]) -> RunSummary {
        let tests = self.filter_tests(tests);
        info!(count = tests.len(), "Running conformance tests");

        for test in tests {
            let result = self.run_comparison(test);
            self.results.push(result);
        }

        self.generate_summary()
    }

    /// Run a single test on both runtimes and compare.
    fn run_comparison(&self, test: &TestCase) -> ComparisonResult {
        let span = span!(Level::INFO, "test", id = test.id, name = test.name);
        let _guard = span.enter();

        info!("Starting test");

        // Run on asupersync
        debug!("Running on asupersync");
        let asupersync_result = self.run_single(test, &self.asupersync);

        // Run on tokio
        debug!("Running on tokio");
        let tokio_result = self.run_single(test, &self.tokio);

        // Compare results
        let comparison = self.compare_results(&asupersync_result, &tokio_result);

        match &comparison {
            ComparisonStatus::BothPassedEquivalent => {
                info!("PASS - both runtimes produced equivalent results");
            }
            ComparisonStatus::TokioOnlyPassed { error } => {
                error!(error = %error, "FAIL - asupersync failed but tokio passed");
            }
            _ => {
                warn!(status = ?comparison, "Test completed with non-ideal status");
            }
        }

        ComparisonResult {
            test_id: test.id.to_string(),
            test_name: test.name.to_string(),
            category: test.category,
            asupersync_result,
            tokio_result,
            comparison,
        }
    }

    fn run_single(&self, test: &TestCase, runtime: &dyn ConformanceRuntime) -> TestResult {
        let start = Instant::now();
        let mut logs = Vec::new();

        // Setup log capture
        let log_collector = LogCollector::new();

        let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            (test.test_fn)(runtime)
        }));

        let duration = start.elapsed();
        logs.extend(log_collector.drain());

        match result {
            Ok(test_result) => test_result,
            Err(panic) => TestResult {
                passed: false,
                duration,
                output: TestOutput::default(),
                logs,
                error: Some(TestError {
                    message: format!("{:?}", panic),
                    kind: ErrorKind::Panic,
                    backtrace: Some(std::backtrace::Backtrace::capture().to_string()),
                }),
            },
        }
    }
}
