1. Registrations must be cleaned up
2. No leaked obligations
3. No dangling wakers
4. Resources properly released

## Cancellation Tests

### Cancel During Read

```rust
#[test]
async fn test_cancel_during_read() {
    let (client, server) = create_connected_pair().await;

    // Start reading (will block waiting for data)
    let read_task = cx.spawn(async move {
        let mut buf = [0u8; 1024];
        client.read(&mut buf).await
    });

    // Cancel before any data sent
    read_task.cancel().await;

    // Verify: task completed with Cancelled outcome
    assert!(matches!(read_task.outcome(), Outcome::Cancelled(_)));

    // Verify: no leaked registration (check reactor len)
    assert_eq!(reactor.len(), 1); // Only server left
}
```

### Cancel During Write

```rust
#[test]
async fn test_cancel_during_write() {
    let (mut client, server) = create_connected_pair().await;

    // Fill the write buffer
    let large_data = vec![0u8; 10_000_000]; // 10MB

    let write_task = cx.spawn(async move {
        client.write_all(&large_data).await
    });

    // Cancel mid-write
    cx.sleep(Duration::from_millis(10)).await;
    write_task.cancel().await;

    // Verify: no leaked resources
    // (Registration cleaned up, partial write is lost - documented behavior)
}
```

