    // Connect to non-routable address (will hang)
    let connect_task = cx.spawn(async {
        TcpStream::connect("10.255.255.1:80").await
    });

    // Cancel after a bit
    cx.sleep(Duration::from_millis(100)).await;
    connect_task.cancel().await;

    // Should complete with Cancelled, not hang forever
