## What

Create a detailed logging system for tests that captures all I/O events, reactor operations, waker dispatches, and timing information to enable thorough debugging.

## Why

The user specifically requested: "make sure that as part of the beads we include comprehensive unit tests and e2e test scripts with great, detailed logging so we can be sure that everything is working perfectly after implementation."

## Design

### LogLevel Enum

```rust
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
pub enum TestLogLevel {
    /// Only errors and failures
    Error,
    /// Warnings and above
    Warn,
    /// General test progress
    Info,
    /// Detailed I/O operations
    Debug,
    /// All events including waker dispatch, polls, syscalls
    Trace,
}
```

### Test Event Types

```rust
#[derive(Debug, Clone)]
pub enum TestEvent {
    // Reactor events
    ReactorPoll { timeout: Option<Duration>, events_returned: usize, duration: Duration },
    ReactorWake { source: &'static str },
    ReactorRegister { token: usize, interest: Interest, source_type: &'static str },
    ReactorDeregister { token: usize },

    // I/O events
    IoRead { token: usize, bytes: usize, would_block: bool },
    IoWrite { token: usize, bytes: usize, would_block: bool },
    IoConnect { addr: String, result: &'static str },
    IoAccept { local: String, peer: String },

    // Waker events
    WakerWake { token: usize, task_id: usize },
    WakerClone { token: usize },
    WakerDrop { token: usize },

    // Task events
    TaskPoll { task_id: usize, result: &'static str },
    TaskSpawn { task_id: usize, name: Option<String> },
    TaskComplete { task_id: usize, outcome: &'static str },

    // Timer events
    TimerScheduled { deadline: Duration, task_id: usize },
    TimerFired { task_id: usize },

    // Custom
    Custom { category: &'static str, message: String },
}
```

### TestLogger Implementation

```rust
pub struct TestLogger {
    level: TestLogLevel,
    events: Mutex<Vec<(Instant, TestEvent)>>,
    start_time: Instant,
}

impl TestLogger {
    pub fn new(level: TestLogLevel) -> Self {
        Self {
            level,
            events: Mutex::new(Vec::new()),
            start_time: Instant::now(),
        }
    }

    pub fn log(&self, event: TestEvent) {
        if self.should_log(&event) {
            let elapsed = self.start_time.elapsed();
            self.events.lock().unwrap().push((elapsed, event.clone()));

            // Also print immediately if verbose
            if self.level >= TestLogLevel::Trace {
                eprintln!("[{:>8.3}ms] {:?}", elapsed.as_secs_f64() * 1000.0, event);
            }
        }
    }

    /// Generate detailed report at end of test
    pub fn report(&self) -> String {
        let events = self.events.lock().unwrap();
        let mut report = String::new();

        writeln!(&mut report, "=== Test Event Log ({} events) ===", events.len()).unwrap();

        for (elapsed, event) in events.iter() {
            writeln!(&mut report, "[{:>8.3}ms] {:?}", 
                elapsed.as_secs_f64() * 1000.0, event).unwrap();
        }

        // Statistics
        writeln!(&mut report, "\n=== Statistics ===").unwrap();
        let polls = events.iter().filter(|(_, e)| matches!(e, TestEvent::ReactorPoll{..})).count();
        let reads = events.iter().filter(|(_, e)| matches!(e, TestEvent::IoRead{..})).count();
        let writes = events.iter().filter(|(_, e)| matches!(e, TestEvent::IoWrite{..})).count();
        let wakes = events.iter().filter(|(_, e)| matches!(e, TestEvent::WakerWake{..})).count();

        writeln!(&mut report, "Reactor polls: {}", polls).unwrap();
        writeln!(&mut report, "I/O reads: {}", reads).unwrap();
        writeln!(&mut report, "I/O writes: {}", writes).unwrap();
        writeln!(&mut report, "Waker wakes: {}", wakes).unwrap();

        report
    }

    /// Assert no busy-loops (excessive polls without events)
    pub fn assert_no_busy_loop(&self, max_empty_polls: usize) {
        let events = self.events.lock().unwrap();
        let empty_polls = events.iter()
            .filter(|(_, e)| matches!(e, TestEvent::ReactorPoll { events_returned: 0, .. }))
            .count();

        assert!(empty_polls <= max_empty_polls, 
            "Busy loop detected: {} empty polls (max {})", empty_polls, max_empty_polls);
    }
}
```

